<template>
    <el-container>
        <el-header height="60px">
            <div class="top">
                <div class="myLogo">
                    <div>
                        <img class="qs" src="./assets/img/logo_58.png" alt="" />
                    </div>
                    <div class="go-to-app" @click="go2App()">
                        <div class="bg-img-change"></div>
                        <div class="app-font">
                            <span>App 下载</span>
                        </div>
                    </div>
                </div>
                <div class="top-right">
                    <el-tabs
                        v-model="activeName"
                        @tab-click="handleClick"
                        style="padding-top: 10px"
                    >
                        <el-tab-pane label="音乐列表" name="home"></el-tab-pane>
                        <el-tab-pane
                            label="音乐包"
                            name="musicList"
                        ></el-tab-pane>
                        <el-tab-pane
                            label="纠纷处理"
                            name="dispute"
                        ></el-tab-pane>
                        <el-tab-pane
                            label="自审制度"
                            name="examine"
                        ></el-tab-pane>
                    </el-tabs>
                    <div class="right-options">
                        <div
                            class="w-lg"
                            v-if="!$store.state?.user?.userInfo.id"
                        >
                            <div class="my-login" @click="login()">登录</div>
                        </div>
                        <el-dropdown v-else>
                            <span class="el-dropdown-link">
                                <el-avatar
                                    :src="$store.state?.user?.userInfo?.avatar"
                                ></el-avatar>
                                <div class="name">
                                    {{ $store.state.user.userInfo.username }}
                                </div>
                            </span>
                            <template #dropdown>
                                <el-dropdown-menu>
                                    <el-dropdown-item @click="handleLogOut"
                                        >退出</el-dropdown-item
                                    >
                                </el-dropdown-menu>
                            </template>
                        </el-dropdown>
                    </div>
                </div>
            </div>
        </el-header>
        <el-main>
            <router-view></router-view>
        </el-main>
        <el-footer>
            <div class="footer-main">
                <div class="cursor" @click="agreenebt('userAgreement')">
                    用户权益保障管理制度
                </div>
                <div class="cursor" @click="agreenebt('technologyAgreement')">
                    技术安全保障管理制度
                </div>
                <div>公司名：北京完美全未来信息技术有限公司</div>
                <br />
                <div>电话：010-578011341 | 邮箱：yangmoyi@pwrd.com</div>
                <div>公司地址：北京市朝阳区望京东路1号4层401内A406</div>
            </div>
        </el-footer>
    </el-container>
</template>
<script>
import { logout } from './service/UserService.js';
export default {
    data() {
        return {
            activeName: 'home',
            light: false
        };
    },
    mounted() {
        // this.activeName = this.$route.path.slice(1);
    },
    watch: {
        $route: {
            deep: true,
            handler: function (v) {
                if (v?.path) {
                    this.activeName = v.path.slice(1);
                }
            }
        }
    },
    methods: {
        go2App() {
            window.open('/s/d');
        },
        login() {
            this.$router.push('/login');
        },
        agreenebt(val) {
            this.activeName = '';
            console.log(this.$router);
            console.log(val);
            this.$router.push({
                name: val
            });
            console.log(this.$router);
        },
        handleClick(val) {
            const item = { ...val };
            this.$router.push(`/${item.paneName}`);
            this.$store.commit('changeAudio', {
                show: false,
                songName: '',
                bgImg: ''
            });
            this.$store.state.audioRef.pause();

        },
        // 退出登录
        handleLogOut() {
            logout().then(() => {
                window.location.href = '/';
                this.$store.commit('clearUser');
            });


        }
    },
};
</script>
<style lang="less" scoped>
.go-to-app {
    width: 100px;
    padding: 15px 25px;
    display: flex;
    cursor: pointer;

    .app-font {
        color: #adadad;
        display: flex;
        justify-content: center;
        flex-direction: column;
    }
    .bg-img-change {
        height: 35px;
        width: 35px;
        background-image: url('./assets/img/app_h.png');
        background-repeat: no-repeat;
        background-position: center;
        background-size: contain;
    }
    &:hover {
        .bg-img-change {
            background-image: url('./assets/img/app_y.png');
        }
        .app-font {
            color: #ffe12d;
        }
    }
}

.myLogo {
    display: flex;
}
.w-lg {
    padding-top: 5px;
}
.my-login {
    cursor: pointer;
    border: 1px #888b8c solid;
    padding: 5px;
    color: #888b8c;
    border-radius: 6px;
    width: 36px;
    text-align: center;
}
.top-right {
    display: flex;
}
.right-options {
    margin-left: 50px;
    padding-top: 10px;
    .name {
        height: 100%;
        display: flex;
        align-items: center;
        justify-content: center;
        cursor: pointer;
        padding-left: 10px;
        color: #5d5757;
    }

    .el-dropdown-link {
        display: flex;
    }
}
.user {
    display: flex;
    .userName {
        color: gray;
    }
}
.cursor:hover {
    text-decoration: underline;
    color: #ffffff;
    cursor: pointer;
}
.el-main {
    min-height: 680px;
    padding: 0 0px !important;
}
.el-footer {
    padding: 0 0px !important;
}
.footer-main {
    padding-top: 21px;
    text-align: center;
    flex-direction: column;
    display: flex;
    color: white;
    font-size: 12px;
    background-color: #353334;
    height: 158px;
    padding: 15px 0px;
}
.top {
    font-size: 13px !important  ;
    display: flex;
    justify-content: space-between;
    // padding-top: 20px;

    .el-tabs__item {
        font-size: 12px;
    }
}
</style>
